'use strict';

/**
 * Creates `.env` with cryptographically random secrets when missing.
 * Safe to run anytime; does not overwrite an existing `.env`.
 */

const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

const root = path.join(__dirname, '..');
const envPath = path.join(root, '.env');

function hex(bytes) {
  return crypto.randomBytes(bytes).toString('hex');
}

if (fs.existsSync(envPath)) {
  console.log('[bootstrap-local-env] .env already exists — leaving it unchanged.');
  process.exit(0);
}

const appKeys = `${hex(16)},${hex(16)}`;

const contents = `# Generated by npm run bootstrap — safe to commit only .env.example, not this file.
HOST=0.0.0.0
PORT=1337

# Comma-separated signing keys (required by Strapi).
APP_KEYS=${appKeys}

API_TOKEN_SALT=${hex(16)}
ADMIN_JWT_SECRET=${hex(32)}
TRANSFER_TOKEN_SALT=${hex(16)}
JWT_SECRET=${hex(32)}

# Wallet session JWT for community-profile routes (optional; defaults to JWT_SECRET).
COMMUNITY_PROFILE_JWT_SECRET=${hex(32)}

# Default local DB — created automatically under .tmp/
DATABASE_CLIENT=sqlite
# DATABASE_FILENAME=.tmp/data.db

# Comma-separated browser origins (Vite dev/preview, admin).
CORS_ORIGIN=http://localhost:5173,http://127.0.0.1:5173,http://localhost:4173,http://127.0.0.1:4173

# Optional: disable Strapi telemetry in dev
STRAPI_TELEMETRY_DISABLED=true
`;

fs.writeFileSync(envPath, contents, 'utf8');
console.log('[bootstrap-local-env] Created .env with random secrets.');
console.log('[bootstrap-local-env] Next: npm install && npm run develop');
console.log('[bootstrap-local-env] Admin UI: http://localhost:1337/admin');
